The following query searches for movies with the characters `pre` in
the `title` field. The query uses:| Field         | Description                                                                                                                                       |
| ------------- | ------------------------------------------------------------------------------------------------------------------------------------------------- |
| maxEdits      | Indicates that only one character variation is allowed in the query string pre to match the query to a word in the documents.                     |
| prefixLength  | Indicates that the first character in the query string pre can't change when matching the query to a word in the documents.                       |
| maxExpansions | Indicates that up to two hundred and fifty six similar terms for pre can be considered when matching the query string to a word in the documents. |**Atlas UI:**Atlas UICopy and paste the following query into the
**Query Editor**, and then click the **Search**
button in the **Query Editor**.```javascript
[
  {
    $search: {
      autocomplete: {
        path: "title",
        query: "pre",
        fuzzy: {
          maxEdits: 1,
          prefixLength: 1,
          maxExpansions: 256
        }
      }
    }
  }
]
```**Shell:**MongoDB Shell```javascript
db.movies.aggregate([
  {
    $search: {
      "autocomplete": {
        "path": "title",
        "query": "pre",
        "fuzzy": {
          "maxEdits": 1,
          "prefixLength": 1,
          "maxExpansions": 256
        }
      }
    }
  },
  {
    $limit: 10
  },
  {
    $project: {
      "_id": 0,
      "title": 1
    }
  }
])

```**Compass:**CompassIn the Aggregations tab of the `movies` collection,
configure each of the following pipeline stages by selecting the stage
from the dropdown and adding the query for that stage. Click
Add Stage to add additional stages.| Pipeline Stage | Query                                                                                                                           |
| -------------- | ------------------------------------------------------------------------------------------------------------------------------- |
| $search        | \{ "autocomplete": \{ "query": "pre", "path": "title", "fuzzy": \{ "maxEdits": 1, "prefixLength": 1, "maxExpansions": 256 } } } |
| $limit         | 10                                                                                                                              |
| $project       | \{ "\_id": 0, "title": 1, }                                                                                                     |**C#:**C#```csharp
using MongoDB.Bson;
using MongoDB.Bson.Serialization.Attributes;
using MongoDB.Bson.Serialization.Conventions;
using MongoDB.Driver;
using MongoDB.Driver.Search;

public class AutocompleteFuzzyExample
{
    private const string MongoConnectionString = "<connection-string>";

    public static void Main(string[] args)
    {
        // allow automapping of the camelCase database fields to our MovieDocument
        var camelCaseConvention = new ConventionPack { new CamelCaseElementNameConvention() };
        ConventionRegistry.Register("CamelCase", camelCaseConvention, type => true);

        // connect to your Atlas cluster
        var mongoClient = new MongoClient(MongoConnectionString);
        var mflixDatabase = mongoClient.GetDatabase("sample_mflix");
        var moviesCollection = mflixDatabase.GetCollection<MovieDocument>("movies");

        // define fuzzy options
        SearchFuzzyOptions fuzzyOptions = new SearchFuzzyOptions()
            {
                MaxEdits = 1,
                PrefixLength = 1,
                MaxExpansions = 256
            };

        // define and run pipeline
        var results = moviesCollection.Aggregate()
            .Search(Builders<MovieDocument>.Search.Autocomplete(movie => movie.Title, "pre", fuzzy: fuzzyOptions))
            .Project<MovieDocument>(Builders<MovieDocument>.Projection
                .Include(movie => movie.Title)
                .Exclude(movie => movie.Id))
            .Limit(10)
            .ToList();

        // print results
        foreach (var movie in results)
        {
            Console.WriteLine(movie.ToJson());
        }
    }
}

[BsonIgnoreExtraElements]
public class MovieDocument
{
    [BsonIgnoreIfDefault]
    public ObjectId Id { get; set; }
    public string Title { get; set; }
}

